#include <stdio.h>

int main() {
	int n;
	int i;
	int a, b = 0, c = 0;
	int sum = 0;
	scanf("%d", &n);
	scanf("%d", &c);
	for(i=1; i<n; i++) {
		a = b;
		b = c;
		scanf("%d", &c);
		if(b + c == 5) {
			printf("Infinite");
			return 0;
		}
		sum += b + c;
		if(a == 3 && b == 1 && c == 2) sum--;
	}
	printf("Finite\n");
	printf("%d", sum);
	return 0;
}

